// Pac-Man Ghost — standalone figurine with api.params
// Revolve-based body, flush eyes, per-label coloring
const { Manifold, CrossSection } = api;

// ─── User-tunable parameters ──────────────────────────────────────────────────
const params = api.params({
  bodyColor: {
    type: 'color',
    default: '#ef0000',
    label: 'Ghost color',
  },
  eyeSize: {
    type: 'number',
    default: 1.0,
    min: 0.6,
    max: 1.5,
    step: 0.1,
    label: 'Eye size multiplier',
  },
  toothCount: {
    type: 'int',
    default: 4,
    min: 2,
    max: 6,
    label: 'Number of teeth',
  },
});

const BODY_COLOR = params.bodyColor;
const EYE_SCALE  = params.eyeSize;
const NUM_TEETH  = params.toothCount;

// ─── Design constants ─────────────────────────────────────────────────────────
const GH_R   = 8.5;   // body radius
const BODY_H = 30.0;  // total height
const HEM_Z  = 6.5;   // bottom hem zone height

// ─── Body profile (revolved around Z axis) ────────────────────────────────────
const pts = [];

// Bottom center
pts.push([0, 0]);
pts.push([GH_R * 0.42, 1.0]);
pts.push([GH_R * 0.66, HEM_Z * 0.5]);
pts.push([GH_R * 0.78, HEM_Z]);

// Waist scallop
pts.push([GH_R * 0.74, HEM_Z + 1.8]);
pts.push([GH_R * 0.77, HEM_Z + 3.8]);

// Swell up to shoulder
pts.push([GH_R * 0.84, HEM_Z + 6.5]);
pts.push([GH_R * 0.94, HEM_Z + 9.5]);

// Full width band
pts.push([GH_R * 1.00, HEM_Z + 12.5]);
pts.push([GH_R * 1.00, HEM_Z + 15.5]);

// Crown arc
const shoulderTopZ = HEM_Z + 15.5;
const crownZ = BODY_H;
const arcSteps = 24;
for (let i = 1; i <= arcSteps; i++) {
  const t = (i / arcSteps) * (Math.PI / 2);
  pts.push([Math.cos(t) * GH_R, shoulderTopZ + Math.sin(t) * (crownZ - shoulderTopZ)]);
}
pts.push([0, crownZ]);

const section = CrossSection.ofPolygons([pts]);
let ghostBody = section.revolve(72);

// ─── Teeth: rounded bumps at the bottom hem ───────────────────────────────────
// Teeth sit just above the base, evenly distributed around the ring
const TOOTH_R    = 2.2;
const TOOTH_RZ   = 1.6;
const toothRingR = GH_R * 0.60;
const toothCZ    = 1.2;  // just above z=0 base

let teethMesh = null;
for (let i = 0; i < NUM_TEETH; i++) {
  const angle = (i / NUM_TEETH) * Math.PI * 2;
  const tx = Math.cos(angle) * toothRingR;
  const ty = Math.sin(angle) * toothRingR;
  const tooth = Manifold.sphere(1, 24)
    .scale([TOOTH_R, TOOTH_R, TOOTH_RZ])
    .translate([tx, ty, toothCZ]);
  teethMesh = teethMesh ? teethMesh.add(tooth) : tooth;
}
ghostBody = ghostBody.add(teethMesh);

// Flat base — cut anything below z=0
ghostBody = ghostBody.subtract(
  Manifold.cube([GH_R * 6, GH_R * 6, 14], true).translate([0, 0, -7])
);

// ─── Eye geometry — flush / embedded in body surface ─────────────────────────
// At EYE_Z the body profile is in the crown arc zone, starting at shoulderTopZ=22.
// The arc center is at (r=0, z=shoulderTopZ); arc radius = GH_R for the horizontal
// component. At z=EYE_Z: arcFrac = (EYE_Z - shoulderTopZ)/(crownZ - shoulderTopZ)
// bodyR_at_eyeZ = cos(asin(arcFrac)) * GH_R
//
// For the eye at x=EYE_SEP, the body surface Y coordinate is:
//   bodyFrontY = -sqrt(bodyR² - EYE_SEP²)   (negative = front, facing -Y)
//
// For a FLUSH eye (front face of ellipsoid tangent to body surface):
//   eyeCY - EYE_RY = bodyFrontY  →  eyeCY = bodyFrontY + EYE_RY
// Adding a small inset (0.4 units) embeds the eye slightly inside the body,
// so the white shows as a slight dimple rather than protruding outward.

const EYE_Z   = 22.5;
const EYE_SEP = 3.2;   // lateral offset (X) from midline

// Compute body radius at EYE_Z height (crown arc zone)
const arcFrac    = (EYE_Z - shoulderTopZ) / (crownZ - shoulderTopZ);
const bodyR_eyeZ = Math.cos(Math.asin(Math.min(1, arcFrac))) * GH_R;

// Body surface Y at the eye X position
const bodyFrontY = -Math.sqrt(Math.max(0.1, bodyR_eyeZ * bodyR_eyeZ - EYE_SEP * EYE_SEP));

// Eye ellipsoid — flat in Y (depth), wide in X, taller in Z for classic ghost eye
const EYE_RX = 3.4 * EYE_SCALE;  // wide oval
const EYE_RY = 1.3 * EYE_SCALE;  // shallow depth: eye mostly in the XZ plane
const EYE_RZ = 4.0 * EYE_SCALE;  // tall oval

// Place eye center so its front face is flush with / just inside the body surface.
// Front of ellipsoid = eyeCY - EYE_RY = bodyFrontY  →  eyeCY = bodyFrontY + EYE_RY
// +0.4 inset buries it slightly so it reads as embedded, not floating on the surface.
const eyeCY = bodyFrontY + EYE_RY + 0.4;

function makeEyeWhite(cx) {
  return Manifold.sphere(1, 48)
    .scale([EYE_RX, EYE_RY, EYE_RZ])
    .translate([cx, eyeCY, EYE_Z]);
}
const leftWhite  = makeEyeWhite(-EYE_SEP);
const rightWhite = makeEyeWhite(EYE_SEP);

// Pupils — sit at the front of the white, slightly inward and down (looking forward)
// Front of white = eyeCY - EYE_RY = bodyFrontY (the body surface plane)
// Pupil center is placed just a bit behind the front so it's visible as a colored oval
const PUP_R  = 1.4 * EYE_SCALE;  // large enough to be clearly visible
const PUP_DX = -0.5;              // slight inward lean
const PUP_DZ = -0.5;              // slight downward
const pupilY  = bodyFrontY + PUP_R * 0.5;  // just behind the front face

function makePupil(cx) {
  return Manifold.sphere(PUP_R, 24)
    .translate([cx + PUP_DX, pupilY, EYE_Z + PUP_DZ]);
}
const leftPupil  = makePupil(-EYE_SEP);
const rightPupil = makePupil(EYE_SEP);

// ─── Label and combine ────────────────────────────────────────────────────────
const bodyLabeled       = api.label(ghostBody,   'body',   { color: BODY_COLOR });
const leftWhiteLabeled  = api.label(leftWhite,   'eyeL',   { color: '#ffffff' });
const rightWhiteLabeled = api.label(rightWhite,  'eyeR',   { color: '#ffffff' });
const leftPupilLabeled  = api.label(leftPupil,   'pupilL', { color: '#2244ee' });
const rightPupilLabeled = api.label(rightPupil,  'pupilR', { color: '#2244ee' });

return bodyLabeled
  .add(leftWhiteLabeled)
  .add(rightWhiteLabeled)
  .add(leftPupilLabeled)
  .add(rightPupilLabeled);

// Colors below were migrated from saved paint into code via api.paint.*
// (the model is now self-colouring; see /ai/colors.md). Edit colours here.
const __pwModel = (() => {
const { Manifold, CrossSection, label } = api;

// =====================================================================
// PAC-MAN + GHOST diorama. Z-up, front faces -Y. ONE watertight solid.
// Pac-Man: clean yellow wedge sphere (mouth open toward -Y).
// Ghost:   domed top, straight body, classic WAVY SCALLOPED skirt,
//          white oval eyes with blue pupils (both looking -Y/left-ish).
// Both fused to a slim rounded base; pellet dots between them.
// =====================================================================

// ---------- PAC-MAN ----------
const PAC_R = 8.5;
const PAC_X = -13;
const PAC_Z = PAC_R + 0.5; // lifted so it rests on the base

const pacSphere = Manifold.sphere(PAC_R, 64).translate([PAC_X, 0, PAC_Z]);

// Mouth wedge: triangle in XY extruded along Z, apex at Pac-Man center,
// opening toward the ghost (+X) and slightly toward the viewer (-Y) so the
// iconic open mouth reads in the 3/4 catalog view. ~33° half-angle.
const mouthHalfAngle = 33 * Math.PI / 180;
const reach = PAC_R + 3;
// Direction the mouth opens: mostly +X, a little -Y.
const dir = Math.atan2(-0.55, 1.0); // bisector angle in XY
const a1 = dir - mouthHalfAngle;
const a2 = dir + mouthHalfAngle;
const mouthProfile = [
  [PAC_X, 0],
  [PAC_X + reach * Math.cos(a1), reach * Math.sin(a1)],
  [PAC_X + reach * Math.cos(a2), reach * Math.sin(a2)],
];
const mouthWedge = Manifold.extrude(CrossSection.ofPolygons([mouthProfile]), PAC_R * 2 + 6)
  .translate([0, 0, PAC_Z - (PAC_R + 3)]);

const pacman = label(pacSphere.subtract(mouthWedge), 'pacman');

// Pac-Man eye: a small dark dot on the upper side (so he reads as a face).
const pacEye = label(
  Manifold.sphere(0.9, 24).translate([PAC_X + 1.2, -2.0, PAC_Z + PAC_R * 0.55]),
  'paceye'
);

// ---------- GHOST ----------
const GH_X = 13;
const GH_R = 7.0; // body radius
const SKIRT_Z = 1.4; // z where the skirt teeth bottom out (base top)
const BODY_TOP = 18.5; // top of the dome

// Dome top: a sphere whose center is placed so its top reaches BODY_TOP.
const domeC = BODY_TOP - GH_R; // dome center z
const dome = Manifold.sphere(GH_R, 64).translate([GH_X, 0, domeC]);

// Straight body: cylinder from the hem line up into the dome (overlaps it).
// The hem (cylinder bottom) sits a few units up so the scalloped teeth hang
// below it as distinct lobes with clear concave notches between them.
const hemZ = SKIRT_Z + 4.2;
const bodyCyl = Manifold.cylinder(domeC - hemZ + 1.0, GH_R, GH_R, 64)
  .translate([GH_X, 0, hemZ]);

let ghostBody = dome.add(bodyCyl);

// Classic WAVY SCALLOPED skirt: a row of rounded teeth across the bottom.
// Each tooth is a vertical capsule (cylinder + sphere cap) hanging from the
// hem down to SKIRT_Z. They overlap the hem and each other only slightly, so
// the gaps between adjacent teeth read as the concave scallops of the hem.
const NUM_TEETH = 4;
const toothR = (GH_R * 1.06) / NUM_TEETH; // fuller lobes, light overlap
const toothBotZ = SKIRT_Z + toothR; // sphere cap center
const toothTopZ = hemZ + 1.2; // overlap up into the body
const spanHalf = GH_R - toothR; // spread across the full width
let teeth = null;
for (let i = 0; i < NUM_TEETH; i++) {
  const t = (i / (NUM_TEETH - 1)) * 2 - 1; // -1..1
  const bx = GH_X + t * spanHalf;
  const col = Manifold.cylinder(toothTopZ - toothBotZ, toothR, toothR, 32)
    .translate([bx, 0, toothBotZ]);
  const cap = Manifold.sphere(toothR, 32).translate([bx, 0, toothBotZ]);
  const tooth = col.add(cap);
  teeth = teeth ? teeth.add(tooth) : tooth;
}
ghostBody = ghostBody.add(teeth);

// Flatten the very bottoms flush so the ghost sits on the base.
const cutter = Manifold.cube([GH_R * 4, GH_R * 4, 8], true)
  .translate([GH_X, 0, SKIRT_Z - 4]);
ghostBody = label(ghostBody.subtract(cutter), 'ghost');

// ---------- GHOST EYES (white ovals) + PUPILS (blue), both looking -Y/left ----------
const eyeZ = domeC + GH_R * 0.15; // upper area, on the dome
const eyeSep = GH_R * 0.42; // horizontal separation
const eyeFront = -(GH_R - 0.6); // protrude from the -Y face, ~overlap

// Oval eye = a sphere scaled wider in X & taller in Z, flatter in Y.
function eyeBall(cx) {
  return Manifold.sphere(1.0, 32)
    .scale([2.0, 1.4, 2.6])
    .translate([GH_X + cx, eyeFront, eyeZ]);
}
const eyes = label(eyeBall(-eyeSep).add(eyeBall(eyeSep)), 'eyes');

// Blue pupils: small spheres set into the lower-left of each eye (looking left),
// sitting proud of the eye front (more -Y).
const pupilY = eyeFront - 1.4; // forward of the eye
const pupilDX = -0.7; // shifted left (looking left)
const pupilDZ = -0.5; // slightly low
function pupil(cx) {
  return Manifold.sphere(0.95, 24)
    .scale([1.0, 1.2, 1.0])
    .translate([GH_X + cx + pupilDX, pupilY, eyeZ + pupilDZ]);
}
const pupils = label(pupil(-eyeSep).add(pupil(eyeSep)), 'pupils');

// ---------- PELLET DOTS between the two characters ----------
const pelletZ = 1.6;

function pellet(x) {
  return Manifold.sphere(0.85, 24).translate([x, 0, pelletZ + 0.5]);
}
const pellets = label(pellet(-3.2).add(pellet(0)).add(pellet(3.2)), 'pellets');

// ---------- SLIM ROUNDED BASE ----------
// Stadium slab = hull of two disks, one under each figure. Top at z = 1.5 so it
// overlaps the bottoms of both the ghost skirt and Pac-Man's lower cap.
const BASE_TOP = 1.5;
const BASE_BOT = -1.0;
const BASE_H = BASE_TOP - BASE_BOT;
const baseR = 10.0;
const baseDiskPac = Manifold.cylinder(BASE_H, baseR, baseR, 64).translate([PAC_X, 0, BASE_BOT]);
const baseDiskGhost = Manifold.cylinder(BASE_H, baseR, baseR, 64).translate([GH_X, 0, BASE_BOT]);
const base = label(baseDiskPac.add(baseDiskGhost).hull(), 'base');

// ---------- ASSEMBLE ----------
return base
  .add(pacman)
  .add(pacEye)
  .add(ghostBody)
  .add(eyes)
  .add(pupils)
  .add(pellets);
})();
api.paint.label("pacman", [1, 0.85, 0.05]);
api.paint.label("paceye", [0.08, 0.06, 0.04]);
api.paint.label("ghost", [0.96, 0.16, 0.2]);
api.paint.label("eyes", [1, 1, 1]);
api.paint.label("pupils", [0.15, 0.3, 0.95]);
api.paint.label("pellets", [1, 0.78, 0.55]);
api.paint.label("base", [0.12, 0.13, 0.2]);
return __pwModel;
